#nullable enable // autogenerated

using System;
using System.Threading.Tasks;
using MVZ2Logic.Archive;
using MVZ2Logic.Maps;
using MVZ2Logic.Scenes;
using PVZEngine;
using PVZEngine.Level;

namespace MVZ2Logic.Talk
{
    public interface ITalkController
    {
        void StartTalk(NamespaceID id, int section, float delay = 1, Action? onEnd = null);
        bool WillSkipTalk(NamespaceID id, int section);
        void AutoSkipTalks(NamespaceID id, int section, Action? onSkipped = null);
        void SimpleStartTalk(NamespaceID groupId, int section, float delay = 0, Action? onSkipped = null, Action? onStarted = null, Action? onEnd = null)
        {
            if (WillSkipTalk(groupId, section))
            {
                AutoSkipTalks(groupId, section, () =>
                {
                    onSkipped?.Invoke();
                    onEnd?.Invoke();
                });
            }
            else
            {
                StartTalk(groupId, section, delay, onEnd);
                onStarted?.Invoke();
            }
        }
    }
    public interface ITalkSystem : IDialogDisplayer, ITalkController
    {
        Task StartSection(int section);
        bool IsInArchive() => GetArchive() != null;
        bool IsInMap() => GetMap() != null;
        bool IsInLevel() => GetLevel() != null;
        LevelEngine? GetLevel();
        IMapInterface? GetMap();
        IArchiveInterface? GetArchive();
    }

}
